import{c as e,S as i,j as t,m as s}from"./chunks/framework.-AwLDeHv.js";const u=JSON.parse('{"title":"GLLVM.jl","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),n={name:"index.md"};function o(l,a,r,d,h,c){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="GLLVM.jl" tabindex="-1">GLLVM.jl <a class="header-anchor" href="#GLLVM.jl" aria-label="Permalink to &quot;GLLVM.jl {#GLLVM.jl}&quot;">​</a></h1><p>A Julia implementation of <strong>Generalised Linear Latent Variable Models</strong> for multivariate species-by-site data. GLLVM.jl targets the Gaussian + phylogenetic slice required for the benchmark study against R&#39;s <code>gllvmTMB</code> package, and is currently a research-stage pilot.</p><h2 id="What-is-a-GLLVM?" tabindex="-1">What is a GLLVM? <a class="header-anchor" href="#What-is-a-GLLVM?" aria-label="Permalink to &quot;What is a GLLVM? {#What-is-a-GLLVM?}&quot;">​</a></h2><p>A GLLVM decomposes the response of each species at each site into a fixed linear predictor, a low-rank latent gradient shared across species (the <em>ordination axes</em>), optional site- and species-level random effects, and an optional phylogenetic component. The latent gradient and random-effect contributions are integrated out analytically under a Gaussian likelihood, giving a marginal model whose covariance structure encodes species-by-species correlation without an explicit species-by-species parameter.</p><h2 id="Why-use-this-package?" tabindex="-1">Why use this package? <a class="header-anchor" href="#Why-use-this-package?" aria-label="Permalink to &quot;Why use this package? {#Why-use-this-package?}&quot;">​</a></h2><ul><li><p><strong>Closed-form Gaussian marginal.</strong> The latent factors are integrated out exactly — no Laplace approximation — so the marginal log-likelihood is evaluated to machine precision and the gradient is well-conditioned.</p></li><li><p><strong>PPCA closed-form warm start.</strong> For models without diagonal random effects or phylogeny the probabilistic-PCA initialiser of Tipping and Bishop (1999) is the exact ML solution, so L-BFGS converges in 0–1 iterations.</p></li><li><p><strong>Reverse-mode-ready AD.</strong> <code>ForwardDiff.jl</code> powers the current gradient; the engine is structured so a hand-coded analytic gradient or a <code>ReverseDiff.jl</code> backend can be slotted in without API change.</p></li></ul><h2 id="Quick-install" tabindex="-1">Quick install <a class="header-anchor" href="#Quick-install" aria-label="Permalink to &quot;Quick install {#Quick-install}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GLLVM&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>The package targets Julia 1.10 and above.</p><h2 id="Status" tabindex="-1">Status <a class="header-anchor" href="#Status" aria-label="Permalink to &quot;Status {#Status}&quot;">​</a></h2><p>GLLVM.jl is a <strong>pilot</strong> for the benchmark study described in the maintainer&#39;s active plan. The API surface in this release covers the Gaussian + multi-tier + phylogenetic path needed to compare against <code>gllvmTMB</code>. Non-Gaussian families, SPDE / spatial random fields and the animal model are out of scope for this version.</p><p>See the <a href="./model">Model</a> page for the math and the <a href="./quickstart">Quick start</a> page for an end-to-end fit.</p>`,12)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
